mapper.select:
SELECT *
FROM EMP_AVT
WHERE EMP_ID = #{empId}
AND AVT_NO = #{avtNo}
AND OWN_AVT_YN = 'Y'

mapper.update:
UPDATE EMPLOYEE
SET EMP_MLG = EMP_MLG - (SELECT AVT_PRICE FROM AVATAR WHERE AVT_NO = #{avtNo})
WHERE EMP_ID = #{empId}

UPDATE EMP_AVT SET OWN_AVT_YN = 'N'
WHERE EMP_ID = #{empId}
AND AVT_NO = #{avtNo}

UPDATE EMP_AVT SET OWN_AVT_WEAR_YN = 'Y'
WHERE EMP_ID = #{empId}
AND AVT_NO = #{avtNo}

UPDATE AVATAR

    AVT_NM = #{avtNm},
    AVT_PRICE = #{avtPrice},
    AVT_CTG = #{avtCtg},
    AVT_YN = #{avtYn}

        , AVT_SAVE_NM = #{avtSaveNm}
        , AVT_O_NM = #{avtONm}


WHERE AVT_NO = #{avtNo}

UPDATE AVATAR
SET AVT_YN = #{avtYn}
WHERE AVT_NO = #{avtNo}
